UPDATE TRIP_SCHEDULE
SET INDEX_SORT = INDEX_SORT - 1
WHERE TRIP_DAY_ID = #{tripDayId,  jdbcType=VARCHAR}
    AND INDEX_SORT > #{indexSort,  jdbcType=INTEGER}

